class OrderDetailsController(val ordersService: OrdersService) extends Controller {

  def get = Action {
    request =>
      val orderId = request.path("id").get.toLong()
      val response = ordersService.getOrderDetailById(orderId, request.user.id)
      Ok(Json.obj("order" -> Json.toJson(response)))
  }
}